const alert = items[0].json.alerts?.[0] || items[0].json;
return [{
  json: {
    alert_name: alert.labels?.alertname || 'UnknownAlert',
    service_name: alert.labels?.service_name || 'unknown',
    severity: alert.labels?.severity || 'info',
    description: alert.annotations?.description || 'No description',
    dashboard_url: alert.annotations?.dashboard_url || '',
    timestamp: alert.startsAt || new Date().toISOString(),
    trace_id: 'trace_' + Math.random().toString(16).slice(2, 18)
  }
}];

const enrichment = $node['🔍 Agent #1: Pre-Enrichment'].json || {};
const router = $node['🎯 Agent #2: Smart Router'].json || {};
const ai = $node['🧠 Agent #3: AI Analysis'].json || {};

return [{
  json: {
    decision: 'CREATE_TICKET',
    agents_executed: {
      enrichment_status: enrichment.code === 0 ? 'success' : 'skipped',
      router_status: router.code === 0 ? 'success' : 'skipped',
      ai_status: ai.response ? 'success' : 'skipped'
    },
    ticket_data: {
      subject: '[' + $node['Parse Alert Data'].json.severity.toUpperCase() + '] ' + $node['Parse Alert Data'].json.alert_name + ' on ' + $node['Parse Alert Data'].json.service_name,
      description: 'Alert: ' + $node['Parse Alert Data'].json.alert_name + '\nService: ' + $node['Parse Alert Data'].json.service_name + '\nSeverity: ' + $node['Parse Alert Data'].json.severity,
      service: $node['Parse Alert Data'].json.service_name,
      severity: $node['Parse Alert Data'].json.severity,
      trace_id: $node['Parse Alert Data'].json.trace_id,
      dashboard_url: $node['Parse Alert Data'].json.dashboard_url,
      enrichment_data: enrichment,
      ai_analysis: ai?.response || 'Pending'
    }
  }
}];
